use assert_cmd::Command;
use predicates::prelude::*;
use serde_json::Value;
use std::fs;
#[cfg(unix)]
use std::os::unix::fs::PermissionsExt;
use std::path::Path;
use tempfile::tempdir;

fn parse_jsonl_events(output: &[u8]) -> Vec<Value> {
    String::from_utf8(output.to_vec())
        .unwrap()
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(|line| serde_json::from_str(line).unwrap())
        .collect()
}

fn event_run_id(events: &[Value]) -> String {
    events
        .iter()
        .find_map(|event| event.get("run_id").and_then(Value::as_str))
        .expect("agent event run_id")
        .to_string()
}

fn parse_single_json(output: &[u8]) -> Value {
    serde_json::from_slice(output).unwrap()
}

fn pending_record_path(workspace: &Path, run_id: &str) -> std::path::PathBuf {
    workspace
        .join(".moonshine")
        .join("agent-permissions")
        .join(format!("{run_id}.json"))
}

fn run_ledger_path(workspace: &Path, run_id: &str) -> std::path::PathBuf {
    workspace
        .join(".moonshine")
        .join("agent-runs")
        .join(format!("{run_id}.jsonl"))
}

fn tool_intent_path(workspace: &Path, run_id: &str, intent_id: &str) -> std::path::PathBuf {
    workspace
        .join(".moonshine")
        .join("agent-tools")
        .join(run_id)
        .join(format!("{intent_id}.json"))
}

