#[test]
fn test_race_execution() {
    let mut cmd = Command::cargo_bin("moonshine").unwrap();
    // Group commands in blocks to ensure sequential execution within branches.
    cmd.arg("-c")
        .arg("{ race; { sleep 1; echo winner; }; { sleep 2; echo loser; } }")
        .assert()
        .success()
        .stdout(predicate::str::contains("winner"))
        .stdout(predicate::str::contains("loser").not());
}

