#[cfg(unix)]
#[test]
fn test_agent_providers_resolves_claude_from_user_local_bin() {
    let dir = tempdir().unwrap();
    let bin_dir = dir.path().join(".local/bin");
    fs::create_dir_all(&bin_dir).unwrap();
    let claude = bin_dir.join("claude");
    fs::write(&claude, "#!/bin/sh\necho 'Claude Code 2.1.200'\n").unwrap();
    let mut perms = fs::metadata(&claude).unwrap().permissions();
    perms.set_mode(0o755);
    fs::set_permissions(&claude, perms).unwrap();

    let assert = Command::cargo_bin("moonshine")
        .unwrap()
        .env("HOME", dir.path())
        .env("PATH", "/usr/bin:/bin")
        .arg("-c")
        .arg("agent providers --json")
        .assert()
        .success();
    let events = parse_jsonl_events(&assert.get_output().stdout);

    assert!(events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("provider_status")
            && event.get("provider").and_then(Value::as_str) == Some("claude")
            && event.get("status").and_then(Value::as_str) == Some("available")
            && event
                .get("content")
                .and_then(Value::as_str)
                .is_some_and(|content| content.contains("Claude Code 2.1.200"))
    }));
}

#[test]
fn test_agent_resume_approve_completes_pending_permission() {
    let dir = tempdir().unwrap();
    let assert = Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg("agent exec --json --permission-mode ask --cwd . -- curl https://example.test")
        .assert()
        .failure();
    let events = parse_jsonl_events(&assert.get_output().stdout);
    let run_id = event_run_id(&events);
    assert!(pending_record_path(dir.path(), &run_id).exists());

    let resume = Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg(format!(
            "agent resume --json --run-id {run_id} --decision approve"
        ))
        .assert()
        .success();
    let resume_events = parse_jsonl_events(&resume.get_output().stdout);

    assert!(resume_events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("permission_decision")
            && event.get("status").and_then(Value::as_str) == Some("approve")
    }));
    assert!(resume_events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("final")
    }));
    assert!(!pending_record_path(dir.path(), &run_id).exists());
}

#[test]
fn test_agent_resume_deny_fails_closed() {
    let dir = tempdir().unwrap();
    let assert = Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg("agent exec --json --permission-mode ask --cwd . -- git push origin main")
        .assert()
        .failure();
    let events = parse_jsonl_events(&assert.get_output().stdout);
    let run_id = event_run_id(&events);

    let resume = Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg(format!(
            "agent resume --json --run-id {run_id} --decision deny"
        ))
        .assert()
        .failure();
    let resume_events = parse_jsonl_events(&resume.get_output().stdout);

    assert!(resume_events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("permission_decision")
            && event.get("status").and_then(Value::as_str) == Some("deny")
    }));
    assert!(resume_events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("error")
            && event.get("verdict").and_then(Value::as_str) == Some("veto")
    }));
    assert!(!pending_record_path(dir.path(), &run_id).exists());
}

