#[test]
fn test_registered_network_aliases_expand_to_wall_diagnostics() {
    let dir = tempdir().unwrap();

    for (alias, expected) in [
        ("ping 1.1.1.1", "wall ping 1.1.1.1"),
        ("traceroute example.com", "wall traceroute example.com"),
        ("tracert example.com", "wall tracert example.com"),
        (
            "wireshark example.com/api",
            "wall wireshark example.com/api",
        ),
        ("dig example.com", "wall dig example.com"),
        ("nslookup example.com", "wall nslookup example.com"),
    ] {
        let mut cmd = Command::cargo_bin("moonshine").unwrap();
        cmd.current_dir(dir.path())
            .arg("--mock")
            .arg("-c")
            .arg(alias)
            .assert()
            .success()
            .stderr(predicate::str::contains(expected));
    }
}

#[test]
fn test_registered_platform_aliases_expand_to_sovereign_adapters() {
    let dir = tempdir().unwrap();

    for (alias, expected) in [
        ("open https://example.com", "wall open https://example.com"),
        ("pbpaste", "wall clipboard-read"),
        ("ip", "wall ip"),
        ("ss", "wall sockets"),
        ("ipconfig", "wall ipconfig"),
        ("sw_vers", "moonbeam platform"),
        ("systemctl", "moonbeam services"),
        ("journalctl", "moonbeam logs"),
        ("tasklist", "moonbeam ps"),
        ("dir .", "rip ls ."),
        ("where moonshine", "rip which moonshine"),
    ] {
        let mut cmd = Command::cargo_bin("moonshine").unwrap();
        cmd.current_dir(dir.path())
            .arg("--mock")
            .arg("-c")
            .arg(alias)
            .assert()
            .success()
            .stderr(predicate::str::contains(expected));
    }
}

#[cfg(unix)]
#[test]
fn test_mutating_platform_adapters_use_sovereign_shims() {
    use std::os::unix::fs::PermissionsExt;

    let dir = tempdir().unwrap();
    let shims = dir.path().join(".moonshine.shims");
    fs::create_dir(&shims).unwrap();

    for (name, body) in [
        ("rip", "#!/bin/sh\necho rip:$*\n"),
        ("moonbeam", "#!/bin/sh\necho moonbeam:$*\n"),
    ] {
        let path = shims.join(name);
        fs::write(&path, body).unwrap();
        let mut perms = fs::metadata(&path).unwrap().permissions();
        perms.set_mode(0o755);
        fs::set_permissions(&path, perms).unwrap();
    }

    Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg("copy /Y source.txt dest.txt")
        .assert()
        .success()
        .stdout(predicate::str::contains(
            "rip:copy --force source.txt dest.txt",
        ));

    Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .arg("-c")
        .arg("taskkill /PID 42 /F /T")
        .assert()
        .success()
        .stdout(predicate::str::contains(
            "moonbeam:kill --pid 42 --force --tree",
        ));
}

