#[test]
fn test_cascading_env() {
    let root = tempdir().unwrap();
    let sub = root.path().join("sub");
    fs::create_dir(&sub).unwrap();

    fs::write(root.path().join(".env"), "ROOT_VAR=root\nOVERRIDE_VAR=root").unwrap();
    fs::write(sub.join(".env"), "SUB_VAR=sub\nOVERRIDE_VAR=sub").unwrap();

    let mut cmd = Command::cargo_bin("moonshine").unwrap();
    // We use a custom config to avoid reading global ones
    let config_path = sub.join(".moonshine.knot");
    fs::write(
        &config_path,
        r#"{"identity":{"did":"did:key:test","secret":"test-secret"},"signed_env_only":false}"#,
    )
    .unwrap();

    cmd.current_dir(&sub)
        .arg("--config")
        .arg(config_path)
        .arg("-c")
        .arg("echo $ROOT_VAR $SUB_VAR $OVERRIDE_VAR")
        .assert()
        .success()
        .stdout(predicate::str::contains("root sub sub"));
}

