/// The model-driven tool loop must degrade cleanly when everything is offline:
/// superserver unreachable (no tool catalog) AND the brain unreachable (closed
/// fat-station port, brain pinned to fat-station so no skymesh traffic). The
/// run falls back to the canned sovereign answer and stdout stays pure NDJSON.
#[test]
fn test_agent_exec_json_tool_loop_degrades_offline() {
    let dir = tempdir().unwrap();
    let assert = Command::cargo_bin("moonshine")
        .unwrap()
        .current_dir(dir.path())
        .env("MOONSHINE_MCP_URL", "http://127.0.0.1:9/mcp")
        .env("MOONSHINE_AGENT_BRAIN", "fat-station")
        .env("FAT_STATION_PORT", "59991")
        .env("MOONSHINE_NO_CACHE", "1")
        .arg("-c")
        .arg("agent exec --json --permission-mode ask --provider sovereign --cwd . -- explain smoke")
        .assert()
        .success();

    let events = parse_jsonl_events(&assert.get_output().stdout);
    let run_id = event_run_id(&events);
    assert!(events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("run_start")
            && event.get("provider").and_then(Value::as_str) == Some("sovereign")
    }));
    assert!(events.iter().any(|event| {
        event.get("type").and_then(Value::as_str) == Some("final")
            && event
                .get("content")
                .and_then(Value::as_str)
                .is_some_and(|content| !content.is_empty())
    }));
    assert!(run_ledger_path(dir.path(), &run_id).exists());
}

