/// Kenoma contract regression guard: with the local browser brain selected and
/// the fat-station down, browser-step must still emit the exact legacy
/// inference-unavailable done action on stdout.
#[test]
fn test_browser_step_local_brain_down_emits_inference_unavailable() {
    let assert = Command::cargo_bin("moonshine")
        .unwrap()
        .env("MOONSHINE_BROWSER_LOCAL", "1")
        .env("FAT_STATION_PORT", "59991")
        .env("MOONSHINE_NO_CACHE", "1")
        .env_remove("RUN_CLOUD_RUN_TESTS")
        .arg("-c")
        .arg("browser-step summarize this page")
        .assert()
        .success();

    let action = parse_single_json(&assert.get_output().stdout);
    assert_eq!(action.get("action").and_then(Value::as_str), Some("done"));
    assert_eq!(
        action.get("answer").and_then(Value::as_str),
        Some("(inference unavailable)")
    );
}
